            <div className="flex flex-wrap gap-2">
              {conditions.map((c) => (
                <button key={c} onClick={() => setCondition(c)} className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${condition === c ? 'bg-black text-white shadow-lg' : 'bg-gray-50 text-gray-400 border border-gray-100'}`}>{c}</button>
              ))}
            </div>
          </div>
        </div>
        <button onClick={handleSubmit} disabled={isSubmitting} className="w-full text-white font-black py-5 rounded-[2.25rem] shadow-xl active:scale-[0.98] transition-all uppercase tracking-[0.2em] text-xs mt-4 bg-black disabled:opacity-50">
          {isSubmitting ? 'Syncing to Campus...' : 'Post Clothing Item'}
        </button>
      </div>
    </div>
  );
};

