];

const ElectronicsListingForm: React.FC<ElectronicsListingFormProps> = ({ onBack, onSuccess, session }) => {
  const [itemName, setItemName] = useState('');
  const [brand, setBrand] = useState('');
  const [condition, setCondition] = useState('Like New');
  const [price, setPrice] = useState('');
  const [location, setLocation] = useState(locations[0]);
  const [description, setDescription] = useState('');
  const [photos, setPhotos] = useState<{file: File, preview: string}[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const conditions = ['New', 'Like New', 'Excellent', 'Good', 'Fair'];
  const MAX_PHOTOS = 10;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (photos.length + files.length > MAX_PHOTOS) {
      alert(`You can only upload up to ${MAX_PHOTOS} photos.`);
      return;
    }

    files.forEach(file => {
      const reader = new FileReader();
      reader.onloadend = () => {
        setPhotos(prev => [...prev, { file, preview: reader.result as string }].slice(0, MAX_PHOTOS));
      };
      reader.readAsDataURL(file);
    });

    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removePhoto = (index: number) => {
    setPhotos(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = async () => {
    if (!itemName.trim()) return alert('Please enter an item name');

    const parsedPrice = parseFloat(price.replace(/[^0-9.]/g, ''));
    if (isNaN(parsedPrice) || parsedPrice <= 0) {
      return alert('Please enter a valid price (numbers only)');
    }

    if (photos.length === 0) {
      return alert('Please upload at least one photo');
    }

    setIsSubmitting(true);

    try {
      const uploadedUrls: string[] = [];

      for (const photo of photos) {
        const fileExt = photo.file.name.split('.').pop();
        const fileName = `${session.user.id}-${Math.random().toString(36).substring(2)}-${Date.now()}.${fileExt}`;
        const filePath = `${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('listings')
          .upload(filePath, photo.file);

        if (uploadError) {
          const msg = uploadError.message.toLowerCase();
          if (msg.includes('bucket not found')) {
            throw new Error('Storage bucket "listings" is missing. Go to the Messages tab to find the SQL Fix script.');
          }
          throw new Error(`[Storage Error] ${uploadError.message}`);
        }

        const { data: { publicUrl } } = supabase.storage
          .from('listings')
          .getPublicUrl(filePath);

        uploadedUrls.push(publicUrl);
      }

      const imageUrlData = uploadedUrls.length > 1 ? JSON.stringify(uploadedUrls) : uploadedUrls[0];
      const { error } = await supabase.from('listings').insert([
        {
          title: itemName.trim(),
          brand: brand.trim(),
          price: parsedPrice,
          condition,
          category: 'Electronics',
          location,
          description: description.trim(),
          seller_id: session?.user?.id,
          image_url: imageUrlData
        }
      ]);

      if (error) {
        throw new Error(`[Database Error] ${error.message} (Code: ${error.code}). Check your RLS policies.`);
      }

      alert('Electronics listed successfully!');
      onSuccess?.();
    } catch (err: any) {
      console.error('Submit Error:', err);
      const msg = err.message || (typeof err === 'string' ? err : JSON.stringify(err));
      alert(`Submission Failed:\n\n${msg}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="bg-purple-600 p-6 flex items-start space-x-4 pt-14 text-white">
        <button onClick={onBack} className="bg-white/20 p-2 rounded-full text-white active:scale-90 transition-transform">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
        </button>
        <div>
          <h1 className="text-white text-xl font-black uppercase tracking-tight">List Electronics</h1>
          <p className="text-white/80 text-[10px] font-bold uppercase tracking-widest">Tech & Gadgets</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-32 no-scrollbar">
        <div className="space-y-3">
          <label className="text-xs font-black text-gray-400 uppercase tracking-widest flex justify-between">
            <span>Photos *</span>
            <span>{photos.length}/{MAX_PHOTOS}</span>
          </label>
          <div className="flex space-x-3 overflow-x-auto no-scrollbar pt-4 pb-2">
            {photos.map((photo, idx) => (
              <div key={idx} className="relative flex-shrink-0">
                <img src={photo.preview} className="w-28 h-28 rounded-3xl object-cover border border-gray-100 shadow-sm" alt="Preview" />
                <button 
                  onClick={() => removePhoto(idx)}
                  className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-lg border-2 border-white active:scale-90 transition-transform z-10"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                  </svg>
                </button>
              </div>
            ))}
            {photos.length < MAX_PHOTOS && (
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-28 h-28 rounded-3xl border-2 border-dashed border-gray-200 bg-gray-50 flex flex-col items-center justify-center text-gray-400 hover:bg-white hover:border-purple-300 transition-all flex-shrink-0 group"
              >
                <div className="bg-white p-2 rounded-xl shadow-sm mb-1 group-hover:scale-110 transition-transform">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-purple-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 4v16m8-8H4" />
                  </svg>
                </div>
                <span className="text-[9px] font-black uppercase tracking-tighter">Add</span>
              </button>
            )}
          </div>
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" multiple className="hidden" />
        </div>

        <div className="space-y-5">
          <div className="space-y-1">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Brand</label>
            <input type="text" value={brand} onChange={(e) => setBrand(e.target.value)} placeholder="Apple, Dell, Sony, Nintendo" className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none text-sm font-bold" />
          </div>

          <div className="space-y-1">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Item Name *</label>
            <input type="text" value={itemName} onChange={(e) => setItemName(e.target.value)} placeholder="MacBook Pro" className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none text-sm font-bold" />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Price ($) *</label>
              <input type="text" inputMode="decimal" value={price} onChange={(e) => setPrice(e.target.value)} placeholder="0.00" className="w-full h-14 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none px-4 text-sm font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Pickup *</label>
              <select value={location} onChange={(e) => setLocation(e.target.value)} className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 appearance-none outline-none text-sm font-bold">
                {locations.map(loc => <option key={loc} value={loc}>{loc}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Description</label>
            <textarea rows={4} value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Specs, battery life, condition details..." className="w-full p-4 bg-gray-50 border border-gray-100 rounded-2xl focus:ring-2 focus:ring-purple-500 outline-none resize-none text-sm font-medium leading-relaxed" />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-black text-gray-400 uppercase tracking-widest">Condition *</label>
            <div className="flex flex-wrap gap-2">
              {conditions.map((c) => (
                <button key={c} onClick={() => setCondition(c)} className={`px-5 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${condition === c ? 'bg-purple-600 text-white shadow-lg shadow-purple-100 scale-105' : 'bg-gray-50 text-gray-400 border border-gray-100'}`}>{c}</button>
              ))}
            </div>
          </div>
        </div>

        <button onClick={handleSubmit} disabled={isSubmitting} className="w-full text-white font-black py-5 rounded-[2rem] shadow-xl active:scale-[0.98] transition-all uppercase tracking-widest text-sm mt-4 bg-purple-600 shadow-purple-100 hover:bg-purple-700 disabled:opacity-50">
          {isSubmitting ? 'Syncing to Campus...' : 'Post Tech Item'}
        </button>
      </div>
    </div>
  );
};

export default ElectronicsListingForm;

import React, { useState, useEffect, useRef } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface Message {
  id: string;
  text: string;
  sender_id: string;
  created_at: string;
}

interface Conversation {
  id: string;
  listing_id: string;
  buyer_id: string;
  seller_id: string;
  other_user_id: string;
}

interface MessagesProps {
  session: any;
  initialConversationId?: string | null;
}

const Messages: React.FC<MessagesProps> = ({ session, initialConversationId }) => {
  const [conversations, setConversations] = useState<Conversation[]>([]);
  const [userNames, setUserNames] = useState<Record<string, string>>({});
  const [userHandles, setUserHandles] = useState<Record<string, string>>({});
  const [userAvatars, setUserAvatars] = useState<Record<string, string>>({});
  const [selectedConversation, setSelectedConversation] = useState<Conversation | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [inputValue, setInputValue] = useState('');
  const [loading, setLoading] = useState(true);
  const [errorType, setErrorType] = useState<'none' | 'table_missing'>('none');
  const scrollRef = useRef<HTMLDivElement>(null);

  const GENERIC_AVATAR = "https://t4.ftcdn.net/jpg/02/15/84/43/360_F_215844325_ttX9vtII6CHedAMhp8asW807z9vhS6CI.jpg";
  const currentUserId = session?.user?.id;

  const chatSetupSQL = `
-- 1. FIX ACCOUNT DELETION ERRORS
ALTER TABLE public.profiles 
DROP CONSTRAINT IF EXISTS profiles_id_fkey,
ADD CONSTRAINT profiles_id_fkey 
FOREIGN KEY (id) REFERENCES auth.users(id) ON DELETE CASCADE;

-- 2. SETUP STORAGE BUCKETS (Fixes "Bucket not found" error)
INSERT INTO storage.buckets (id, name, public)
VALUES ('listings', 'listings', true), ('avatars', 'avatars', true)
ON CONFLICT (id) DO NOTHING;

-- Storage Policies
DO $$ BEGIN
  DROP POLICY IF EXISTS "Public Access" ON storage.objects;
  CREATE POLICY "Public Access" ON storage.objects FOR SELECT USING (true);
EXCEPTION WHEN others THEN NULL; END $$;

DO $$ BEGIN
  DROP POLICY IF EXISTS "Auth Upload" ON storage.objects;
  CREATE POLICY "Auth Upload" ON storage.objects FOR INSERT WITH CHECK (auth.role() = 'authenticated');
EXCEPTION WHEN others THEN NULL; END $$;

-- 3. CREATE FULL MARKETPLACE SCHEMA
CREATE TABLE IF NOT EXISTS public.listings (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  title text NOT NULL,
  brand text,
  size text,
  gender text,
  price numeric NOT NULL,
  condition text NOT NULL,
  category text NOT NULL,
  location text NOT NULL,
  description text,
  image_url text NOT NULL,
  seller_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.favorites (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  user_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  listing_id uuid NOT NULL REFERENCES public.listings(id) ON DELETE CASCADE,
  UNIQUE(user_id, listing_id)
);

CREATE TABLE IF NOT EXISTS public.conversations (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  listing_id uuid REFERENCES public.listings(id) ON DELETE CASCADE,
  buyer_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  seller_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.messages (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  conversation_id uuid REFERENCES public.conversations(id) ON DELETE CASCADE,
  sender_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  text text NOT NULL
);

-- 4. ENABLE RLS & POLICIES
ALTER TABLE public.listings ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.favorites ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.conversations ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.messages ENABLE ROW LEVEL SECURITY;

-- Listings Policies
DROP POLICY IF EXISTS "Public View" ON public.listings;
CREATE POLICY "Public View" ON public.listings FOR SELECT USING (true);
DROP POLICY IF EXISTS "Auth Insert" ON public.listings;
CREATE POLICY "Auth Insert" ON public.listings FOR INSERT WITH CHECK (auth.uid() = seller_id);
DROP POLICY IF EXISTS "Owner Delete" ON public.listings;
CREATE POLICY "Owner Delete" ON public.listings FOR DELETE USING (auth.uid() = seller_id);

-- Chat Policies
DROP POLICY IF EXISTS "Users see conversations" on public.conversations;
create policy "Users see conversations" on public.conversations for select using (auth.uid() = buyer_id or auth.uid() = seller_id);
DROP POLICY IF EXISTS "Users start conversations" on public.conversations;
create policy "Users start conversations" on public.conversations for insert with check (auth.uid() = buyer_id);
DROP POLICY IF EXISTS "Users see messages" on public.messages;
create policy "Users see messages" on public.messages for select using (exists (select 1 from public.conversations where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())));
DROP POLICY IF EXISTS "Users send messages" on public.messages;
create policy "Users send messages" on public.messages for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    if (currentUserId) {
      fetchConversations(currentUserId);
    } else {
      setLoading(false);
    }
  }, [currentUserId]);

  useEffect(() => {
    if (!initialConversationId || conversations.length === 0) return;
    const match = conversations.find((c) => c.id === initialConversationId);
    if (match) setSelectedConversation(match);
  }, [initialConversationId, conversations]);

  const fetchConversations = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('conversations')
        .select(`
          id, listing_id, buyer_id, seller_id, created_at
        `)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`)
        .order('created_at', { ascending: false });

      if (error) {
        if ((error as any).code === '42P01') setErrorType('table_missing');
        throw error;
      }

      if (data) {
        const grouped = data.reduce((acc: Conversation[], conv: any) => {
          const otherId = conv.buyer_id === userId ? conv.seller_id : conv.buyer_id;
          if (otherId === userId) return acc;
          const alreadyExists = acc.find(c => c.other_user_id === otherId);
          if (!alreadyExists) {
            acc.push({ ...conv, other_user_id: otherId });
          }
          return acc;
        }, []);

        setConversations(grouped);
        grouped.forEach((conv: any) => fetchAndCacheUserProfile(conv.other_user_id));
      }
    } catch (err: any) {
      console.error('Error fetching conversations:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const fetchAndCacheUserProfile = async (userId: string) => {
    if (!userId) return;
    try {
      const { data: profile } = await supabase
        .from('profiles')
        .select('full_name, avatar_url, username')
        .eq('id', userId)
        .maybeSingle();

      if (profile) {
        const identity = profile.full_name || (profile.username ? `@${profile.username}` : `Student ${userId.slice(0, 4).toUpperCase()}`);
        setUserNames((s) => ({ ...s, [userId]: identity }));
        setUserHandles((s) => ({ ...s, [userId]: profile.username ? `@${profile.username}` : `student` }));

        const isDefault = !profile.avatar_url || profile.avatar_url.includes('dicebear') || profile.avatar_url === GENERIC_AVATAR;
        if (!isDefault) {
          setUserAvatars((s) => ({ ...s, [userId]: profile.avatar_url }));
        }
      } else {
        const fallback = userId.slice(0, 4).toUpperCase();
        setUserNames((s) => ({ ...s, [userId]: `Student ${fallback}` }));
        setUserHandles((s) => ({ ...s, [userId]: `@student${fallback.toLowerCase()}` }));
      }
    } catch (err) {}
  };

  const fetchMessages = async (convId: string) => {
    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });
    if (error) console.error('Error fetching messages:', error.message || error);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation) return;
    fetchMessages(selectedConversation.id);
    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages((prev) => {
          if (prev.some(m => m.id === payload.new.id)) return prev;
          return [...prev, payload.new as Message];
        });
      })
      .subscribe();
    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedConversation]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;
    const text = inputValue.trim();
    setInputValue('');
    await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });
  };

  const getUserDisplayName = (userId: string) => userNames[userId] || 'Syncing...';
  const getUserHandle = (userId: string) => userHandles[userId] || '...';
  const getAvatar = (userId: string) => userAvatars[userId] || GENERIC_AVATAR;

  if (errorType === 'table_missing') {
    return (
      <div className="flex flex-col h-full bg-white p-8 justify-center items-center text-center space-y-4">
        <div className="bg-orange-50 p-6 rounded-[2rem] text-orange-600">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
          </svg>
        </div>
        <div className="space-y-2">
          <h2 className="text-xl font-black text-gray-900 uppercase tracking-tight">Full Infrastructure Sync</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">Run this final script in Supabase to fix all errors (Storage, Listings, and Chat).</p>
        </div>
        <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[8px] overflow-x-auto whitespace-pre font-mono h-48 no-scrollbar border border-white/10 shadow-inner select-all w-full">{chatSetupSQL}</pre>
        <button onClick={() => window.location.reload()} className="w-full bg-orange-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-[11px] shadow-xl shadow-orange-100 active:scale-95 transition-all">Reload App</button>
      </div>
    );
  }

  if (selectedConversation) {
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-4 px-6 flex items-center border-b border-gray-100 space-x-4 bg-white/80 backdrop-blur-md sticky top-0 z-50">
          <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-2 text-gray-400">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div className="flex items-center space-x-3">
            <img src={getAvatar(selectedConversation.other_user_id)} className="w-10 h-10 rounded-full bg-gray-50 border border-gray-100 object-cover shadow-sm" alt="Avatar" />
            <div className="overflow-hidden">
              <h3 className="text-sm font-black text-gray-900 tracking-tight truncate">{getUserDisplayName(selectedConversation.other_user_id)}</h3>
            </div>
          </div>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 scroll-smooth no-scrollbar">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'} animate-in fade-in zoom-in duration-200`}>
                <div className={`max-w-[80%] px-5 py-3 rounded-[1.5rem] text-sm shadow-sm ${isMe ? 'bg-orange-500 text-white rounded-br-none' : 'bg-gray-100 text-gray-800 rounded-bl-none font-medium'}`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-4 pb-28 bg-white border-t border-gray-100">
          <div className="flex items-center space-x-2 max-w-md mx-auto">
            <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()} placeholder="Message..." className="flex-1 bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3.5 text-sm focus:ring-2 focus:ring-orange-100 transition-all outline-none" />
            <button onClick={handleSendMessage} className="bg-orange-500 text-white p-3.5 rounded-2xl shadow-lg shadow-orange-100 active:scale-90 transition-transform">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-16 pb-6 px-8 border-b border-gray-50">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Messages</h1>
        <div className="flex items-center space-x-2 mt-1">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
          <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">UTD Campus Network</span>
        </div>
      </div>
      <div className="flex-1 overflow-y-auto pb-24 p-4 space-y-3 bg-gray-50/30 no-scrollbar">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-3">
            <div className="w-8 h-8 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Syncing Inbox...</p>
          </div>
        ) : conversations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-32 text-gray-300 text-center px-8">
            <div className="bg-white p-8 rounded-[3rem] mb-6 shadow-sm border border-gray-100 opacity-50">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" /></svg>
            </div>
            <h3 className="text-gray-900 font-bold mb-1 text-lg uppercase tracking-tight">Inbox Empty</h3>
            <p className="text-xs font-medium text-gray-400">Message a student to start a chat</p>
          </div>
        ) : (
          conversations.map((chat) => (
            <div 
              key={chat.id} 
              onClick={() => setSelectedConversation(chat)}
              className="p-5 flex items-center space-x-4 bg-white rounded-[2rem] border border-gray-100 shadow-sm active:scale-[0.98] transition-all cursor-pointer hover:shadow-md hover:border-[3px] hover:border-orange-500 group"
            >
              <div className="relative">
                <img src={getAvatar(chat.other_user_id)} className="w-14 h-14 rounded-2xl bg-orange-50 border border-orange-100 object-cover shadow-inner group-hover:scale-105 transition-transform" alt="Avatar" />
              </div>
              <div className="flex-1 overflow-hidden">
                <h3 className="font-black text-gray-900 text-lg tracking-tight truncate">{getUserDisplayName(chat.other_user_id)}</h3>
                <div className="flex items-center space-x-1.5 mt-0.5">
                  <span className="text-[10px] font-black text-orange-500 uppercase tracking-widest">{getUserHandle(chat.other_user_id)}</span>
