                    </svg>
                  </button>
                  <button 
                    onClick={nextPhoto}
                    className="absolute right-6 top-1/2 -translate-y-1/2 bg-white/40 hover:bg-white/80 backdrop-blur-md p-3 rounded-full shadow-lg text-gray-900 active:scale-75 transition-all opacity-0 group-hover:opacity-100 border border-white/20"
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
