                className={`h-1.5 rounded-full transition-all duration-300 ${i === currentPhotoIdx ? 'w-6 bg-[#F15A24]' : 'w-1.5 bg-gray-200'}`}
              ></button>
            ))}
          </div>
          <span className="text-[10px] font-black text-gray-300 tracking-[0.2em] uppercase">
            Frame {currentPhotoIdx + 1} of {photos.length}
