import React, { useState, useEffect } from 'react';
import EditProfile from './EditProfile';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ProfileProps {
  session: any;
  onSelectItem?: (item: any) => void;
  onGoHome?: () => void;
}

const Profile: React.FC<ProfileProps> = ({ session, onSelectItem, onGoHome }) => {
  const [activeTab, setActiveTab] = useState<'active' | 'favorites'>('active');
  const [isEditing, setIsEditing] = useState(false);
  const [myListings, setMyListings] = useState<any[]>([]);
  const [favoriteListings, setFavoriteListings] = useState<any[]>([]);
  const [profile, setProfile] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const GENERIC_AVATAR = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'%3E%3Crect width='100' height='100' rx='35' fill='white'/%3E%3Crect x='2' y='2' width='96' height='96' rx='34' fill='none' stroke='%23FF8C42' stroke-width='1.5' stroke-opacity='0.2'/%3E%3Ccircle cx='50' cy='44' r='18' fill='%23B0B0B0'/%3E%3Cpath d='M22 86c0-15 12-25 28-25s28 10 28 25v4H22v-4z' fill='%23B0B0B0'/%3E%3C/svg%3E";

  useEffect(() => {
    fetchAllData();
    if (isSupabaseConfigured && session?.user?.id) {
      const channel = supabase
        .channel('profile-sync')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => fetchMyListings())
        .on('postgres_changes', { event: '*', schema: 'public', table: 'favorites' }, () => fetchFavorites())
        .on('postgres_changes', { event: '*', schema: 'public', table: 'profiles' }, () => fetchProfile())
        .subscribe();
      return () => { supabase.removeChannel(channel); };
    }
  }, [session?.user?.id]);

  const fetchAllData = async () => {
    if (!isSupabaseConfigured || !session?.user?.id) return setLoading(false);
    setLoading(true);
    await Promise.all([fetchMyListings(), fetchFavorites(), fetchProfile()]);
    setLoading(false);
  };

  const fetchProfile = async () => {
    const { data } = await supabase.from('profiles').select('*').eq('id', session.user.id).maybeSingle();
    if (data) setProfile(data);
  };

  const fetchMyListings = async () => {
    const { data } = await supabase.from('listings').select('*').eq('seller_id', session.user.id).order('created_at', { ascending: false });
    if (data) setMyListings(data);
  };

  const fetchFavorites = async () => {
    const { data: favs } = await supabase.from('favorites').select('listing_id').eq('user_id', session.user.id);
    if (favs && favs.length > 0) {
      const { data: items } = await supabase.from('listings').select('*').in('id', favs.map(f => f.listing_id));
      setFavoriteListings(items || []);
    } else {
      setFavoriteListings([]);
    }
  };

  const handleLogout = async () => isSupabaseConfigured && await supabase.auth.signOut();

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try { return imageUrl.startsWith('[') ? JSON.parse(imageUrl)[0] : imageUrl; } catch { return imageUrl; }
  };

  if (isEditing) return (
    <EditProfile 
      user={{ 
        firstName: profile?.full_name?.split(' ')[0] || '', 
        lastName: profile?.full_name?.split(' ').slice(1).join(' ') || '', 
        username: profile?.username || '', 
        avatar: profile?.avatar_url || GENERIC_AVATAR 
      }} 
      session={session} 
      onBack={() => setIsEditing(false)} 
    />
  );

  const displayName = profile?.full_name || session?.user?.email?.split('@')[0] || 'User';
  const displayAvatar = profile?.avatar_url || GENERIC_AVATAR;

  return (
    <div className="h-full bg-white flex flex-col">
      <div className="relative h-64 bg-[#FF733B] p-8 flex flex-col justify-end overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="absolute bottom-0 left-0 w-full h-32 bg-gradient-to-t from-black/20 to-transparent"></div>

        <button 
          onClick={handleLogout} 
          className="absolute top-12 right-6 bg-white/20 p-2.5 rounded-2xl text-white backdrop-blur-md active:scale-90 border border-white/10 z-20 transition-all hover:bg-white/30"
          aria-label="Logout"
        >
          <svg viewBox="0 0 24 24" className="h-5 w-5 fill-current" xmlns="http://www.w3.org/2000/svg">
            <path d="M10 2L3 4.5C2.4 4.7 2 5.2 2 5.8V18.2C2 18.8 2.4 19.3 3 19.5L10 22V2Z" />
            <circle cx="7.5" cy="12" r="0.8" className="fill-white/80" />
            <path d="M12 5H20V9" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" fill="none" />
            <path d="M12 19H20V15" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" fill="none" />
            <path d="M12 12H21.5M21.5 12L18.5 9M21.5 12L18.5 15" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" fill="none" />
          </svg>
        </button>

        <div className="flex items-center space-x-5 relative z-10">
          <div className="relative group cursor-pointer" onClick={() => setIsEditing(true)}>
            <img 
              src={displayAvatar} 
              className="w-20 h-20 rounded-[2rem] border-4 border-white/20 object-cover shadow-2xl group-hover:brightness-90 transition-all bg-white" 
              alt="Profile" 
            />
            <div className="absolute -bottom-1 -right-1 bg-white p-1.5 rounded-xl shadow-lg border border-gray-100 group-hover:scale-110 transition-transform">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-[#FF733B]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
            </div>
          </div>
          <div className="text-white">
            <h2 className="text-2xl font-black drop-shadow-sm">{displayName}</h2>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] bg-white/20 px-2 py-0.5 rounded-md inline-block backdrop-blur-sm border border-white/10 mt-1">@{profile?.username || 'student'}</p>
          </div>
        </div>
      </div>

      <div className="flex bg-white border-b border-gray-100 sticky top-0 z-20">
        <button onClick={() => setActiveTab('active')} className={`flex-1 py-5 text-[10px] font-black uppercase tracking-[0.15em] relative transition-all ${activeTab === 'active' ? 'text-[#FF733B]' : 'text-gray-400'}`}>
          My Items ({myListings.length})
          {activeTab === 'active' && <div className="absolute bottom-0 left-8 right-8 h-1 bg-[#FF733B] rounded-t-full"></div>}
        </button>
        <button onClick={() => setActiveTab('favorites')} className={`flex-1 py-5 text-[10px] font-black uppercase tracking-[0.15em] relative transition-all ${activeTab === 'favorites' ? 'text-[#FF733B]' : 'text-gray-400'}`}>
          Favorites ({favoriteListings.length})
          {activeTab === 'favorites' && <div className="absolute bottom-0 left-8 right-8 h-1 bg-[#FF733B] rounded-t-full"></div>}
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 bg-gray-50/30 no-scrollbar pb-32">
        {loading ? (
          <div className="flex justify-center py-20"><div className="w-8 h-8 border-4 border-[#FF733B] border-t-transparent rounded-full animate-spin"></div></div>
        ) : (activeTab === 'active' ? myListings : favoriteListings).length > 0 ? (
          <div className="grid grid-cols-2 gap-4">
            {(activeTab === 'active' ? myListings : favoriteListings).map((item) => (
              <div key={item.id} onClick={() => onSelectItem?.(item)} className="bg-white p-1.5 rounded-[1.75rem] border-2 border-[#F6F7F9] shadow-sm active:scale-[0.98] transition-all cursor-pointer hover:border-[#FF733B] hover:shadow-lg hover:shadow-orange-100/30 overflow-hidden">
                <div className="relative aspect-[4/5] rounded-[1.5rem] overflow-hidden mb-2 bg-gray-50">
                  <img src={getThumbnail(item.image_url)} className="w-full h-full object-cover transition-transform duration-700 hover:scale-105" alt={item.title} />
                </div>
                <div className="flex flex-col space-y-1 px-2 pb-2 h-20 justify-between">
                  <div>
                    <span className="text-[7px] font-black text-orange-400 uppercase tracking-[0.15em] block h-3 truncate leading-none">
                      {item.brand || item.category}
                    </span>
                    <h3 className="font-black text-[#1A1A1A] text-[11px] tracking-tight line-clamp-2 leading-tight min-h-[1.75rem] uppercase">
                      {item.title}
                    </h3>
                  </div>
                  <div className="flex justify-between items-baseline pt-1">
                    <p className="text-[#FF733B] font-black text-xs tracking-tighter">${Number(item.price).toFixed(2)}</p>
                    <span className="text-[7px] font-bold text-[#B0B0B0] uppercase tracking-wider text-right truncate flex-1 ml-2">
                      {item.location}
                    </span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-20 text-center px-10 border-2 border-dashed border-gray-100 rounded-[3rem] mx-4 my-8">
            <p className="text-[10px] font-black text-gray-300 uppercase tracking-[0.2em] leading-relaxed">No Results</p>
          </div>
        )}
      </div>

      <div className="p-4 border-t border-gray-100 bg-white sticky bottom-0 flex space-x-3 z-30 shadow-[0_-10px_20px_rgba(0,0,0,0.02)]">
        <button onClick={() => setIsEditing(true)} className="flex-1 border-2 border-[#FF733B] text-[#FF733B] font-black py-4 rounded-2xl text-[10px] uppercase tracking-[0.2em] active:scale-95 transition-all">Edit Identity</button>
        <button onClick={onGoHome} className="flex-1 bg-[#FF733B] text-white font-black py-4 rounded-2xl text-[10px] uppercase tracking-[0.2em] shadow-xl shadow-orange-100 active:scale-95 transition-all">Marketplace</button>
      </div>
    </div>
  );
};

export default Profile;

import React, { useState } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface LoginProps {
  onForgotPassword?: () => void;
}

const Login: React.FC<LoginProps> = ({ onForgotPassword }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [isSignUp, setIsSignUp] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isSupabaseConfigured) {
      setError("Marketplace configuration missing.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (isSignUp) {
      const { error: signUpError } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: {
            full_name: fullName,
          }
        }
      });
      if (signUpError) setError(signUpError.message);
    } else {
      const { error: authError } = await supabase.auth.signInWithPassword({
        email,
        password,
      });
      if (authError) setError(authError.message);
    }

    setIsLoading(false);
  };

  return (
    <div className="h-full bg-white flex flex-col px-8 py-16 animate-in fade-in duration-500 relative overflow-hidden">
      <div className="flex flex-col items-center justify-center mt-12 mb-10 text-center">
        <h1 className="text-6xl font-[900] text-[#FF733B] tracking-tighter mb-12 leading-none">
          Hucksta
        </h1>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-3">
          {isSignUp && (
            <input
              type="text"
              value={fullName}
              onChange={(e) => setFullName(e.target.value)}
              placeholder="Full Name"
              required
              className="w-full h-14 px-6 bg-[#F6F7F9] rounded-2xl text-gray-800 border-2 border-transparent outline-none focus:bg-white focus:border-[#FF733B] transition-all placeholder-gray-300 font-bold"
            />
          )}
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Email"
            required
            className="w-full h-14 px-6 bg-[#F6F7F9] rounded-2xl text-gray-800 border-2 border-transparent outline-none focus:bg-white focus:border-[#FF733B] transition-all placeholder-gray-300 font-bold"
          />
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Password"
            required
            className="w-full h-14 px-6 bg-[#F6F7F9] rounded-2xl text-gray-800 border-2 border-transparent outline-none focus:bg-white focus:border-[#FF733B] transition-all placeholder-gray-300 font-bold"
          />
        </div>

        {error && <p className="text-xs text-red-500 px-1 font-medium">{error}</p>}

        <div className="flex justify-end px-1">
          <button 
            type="button"
            onClick={onForgotPassword}
            className="text-[10px] font-black uppercase tracking-widest text-[#FF733B] hover:text-orange-700 transition-colors"
          >
            Forgot Password?
          </button>
        </div>

        <button
          type="submit"
          disabled={isLoading}
          className="w-full h-16 bg-[#FF733B] text-white font-black uppercase tracking-[0.15em] text-xs rounded-[2rem] active:scale-[0.98] transition-all shadow-xl shadow-orange-100/30 disabled:opacity-50 mt-4"
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin mx-auto"></div>
          ) : (
            isSignUp ? 'Create Account' : 'Continue'
          )}
        </button>
      </form>

      <div className="mt-8 text-center">
        <button 
          onClick={() => setIsSignUp(!isSignUp)}
          className="text-[11px] font-black uppercase tracking-widest text-[#FF733B] hover:underline"
        >
          {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
        </button>
      </div>

      <div className="mt-auto mb-4 text-center">
        <p className="text-[10px] font-black text-gray-300 uppercase tracking-[0.3em] leading-relaxed max-w-[280px] mx-auto">
          Secure campus marketplace for Comets
        </p>
      </div>
    </div>
  );
};

export default Login;

import React, { useState, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface MarketplaceProps {
  session: any;
  onSelectItem?: (item: any) => void;
  onFavoriteChange?: (isSaved: boolean) => void;
}

const Marketplace: React.FC<MarketplaceProps> = ({ session, onSelectItem, onFavoriteChange }) => {
  const [activeCategory, setActiveCategory] = useState('Clothing');
  const [searchQuery, setSearchQuery] = useState('');
  const [listings, setListings] = useState<any[]>([]);
  const [favorites, setFavorites] = useState<Set<string>>(new Set());
  const [loading, setLoading] = useState(true);
  const [burstingId, setBurstingId] = useState<string | null>(null);

  const categories = [
    { name: 'Clothing', icon: '👕' },
    { name: 'Furniture', icon: '🪑' },
    { name: 'Electronics', icon: '💻' }
  ];

  useEffect(() => {
    fetchListings();
    if (session?.user?.id) {
      fetchFavorites();
    }

    if (isSupabaseConfigured) {
      const channel = supabase
        .channel('marketplace-realtime')
        .on('postgres_changes', { event: '*', schema: 'public', table: 'listings' }, () => fetchListings())
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, [session?.user?.id]);

  const fetchListings = async () => {
    if (!isSupabaseConfigured) {
      setLoading(false);
      return;
    }

    try {
      const { data, error } = await supabase
        .from('listings')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (data) setListings(data);
    } catch (err: any) {
      console.error('Fetch error:', err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchFavorites = async () => {
    if (!session?.user?.id) return;
    try {
      const { data, error } = await supabase
        .from('favorites')
        .select('listing_id')
        .eq('user_id', session.user.id);
      if (error) throw error;
      if (data) setFavorites(new Set(data.map(f => f.listing_id)));
    } catch (err: any) {
      console.error('Error fetching favorites:', err.message);
    }
  };

  const toggleFavorite = async (e: React.MouseEvent, listingId: string) => {
    e.stopPropagation();
    if (!session?.user?.id) return;

    const isFavorited = favorites.has(listingId);
    setBurstingId(listingId);
    setTimeout(() => setBurstingId(null), 400);

    const nextFavorites = new Set(favorites);
    if (isFavorited) nextFavorites.delete(listingId);
    else nextFavorites.add(listingId);
    setFavorites(nextFavorites);

    onFavoriteChange?.(!isFavorited);

    try {
      if (isFavorited) {
        await supabase
          .from('favorites')
          .delete()
          .eq('user_id', session.user.id)
          .eq('listing_id', listingId);
      } else {
        await supabase
          .from('favorites')
          .insert({ user_id: session.user.id, listing_id: listingId });
      }
    } catch (err: any) {
      console.error('Error toggling favorite:', err.message);
    }
  };

  // Fixed the variable name typo in the filter logic
  const displayedItems = listings.filter(item => {
    const matchesCategory = item.category === activeCategory;
    const searchLower = searchQuery.toLowerCase();
    const matchesSearch = item.title.toLowerCase().includes(searchLower);
    return matchesCategory && matchesSearch;
  });

  const getThumbnail = (imageUrl: string) => {
    if (!imageUrl) return 'https://images.unsplash.com/photo-1515886657613-9f3515b0c78f?auto=format&fit=crop&q=80&w=400';
    try {
      if (imageUrl.startsWith('[') && imageUrl.endsWith(']')) {
        return JSON.parse(imageUrl)[0];
      }
      return imageUrl;
    } catch (e) {
      return imageUrl;
    }
  };

  return (
    <div className="flex flex-col h-full bg-white overflow-y-auto no-scrollbar">
      {/* Brand Header */}
      <div className="pt-12 px-6 pb-2 text-center">
        <h1 className="text-[40px] font-[900] text-[#FF733B] tracking-tighter leading-none">Hucksta</h1>
      </div>

      {/* Search Bar */}
      <div className="px-6 mb-6 mt-4">
        <div className="relative group">
          <div className="absolute inset-y-0 left-5 flex items-center pointer-events-none z-10">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-gray-400 group-focus-within:text-[#FF733B] transition-colors" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
          </div>
          <input 
            type="text" 
            placeholder="Search campus items..." 
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="w-full bg-[#F6F7F9] rounded-2xl py-4 pl-12 pr-6 text-xs font-semibold focus:outline-none transition-all placeholder-gray-400 border-2 border-transparent hover:border-[#FF733B] focus:border-[#FF733B] focus:bg-white"
          />
        </div>
      </div>

      {/* Category Tabs */}
      <div className="flex space-x-2 px-6 mb-6 overflow-x-auto no-scrollbar">
        {categories.map((cat) => (
          <button
            key={cat.name}
            onClick={() => setActiveCategory(cat.name)}
            className={`flex items-center space-x-2 px-5 py-3 rounded-2xl whitespace-nowrap transition-all active:scale-95 ${
              activeCategory === cat.name 
                ? 'bg-[#FF733B] text-white shadow-md shadow-orange-100' 
                : 'bg-[#F6F7F9] text-[#707E8C] font-black'
            }`}
          >
            <span className="text-lg">{cat.icon}</span>
            <span className="text-[10px] font-black uppercase tracking-widest">{cat.name}</span>
          </button>
        ))}
      </div>

      {/* Item Grid */}
      <div className="px-4 pb-32">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20">
            <div className="w-8 h-8 border-4 border-[#FF733B] border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : displayedItems.length > 0 ? (
          <div className="grid grid-cols-2 gap-4">
            {displayedItems.map((item) => {
              const isOwner = session?.user?.id === item.seller_id;
              return (
                <div 
                  key={item.id} 
                  onClick={() => onSelectItem?.(item)}
                  className="flex flex-col group active:scale-[0.98] transition-all cursor-pointer bg-white rounded-[1.75rem] p-1.5 border-2 border-[#F6F7F9] shadow-sm hover:border-[#FF733B] hover:shadow-lg hover:shadow-orange-100/30 overflow-hidden"
                >
                  <div className="relative aspect-[4/5] rounded-[1.5rem] overflow-hidden mb-2 bg-gray-50">
                    <img 
                      src={getThumbnail(item.image_url)} 
                      alt={item.title} 
                      className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" 
                    />

                    {/* Quality Enhancement Overlay */}
                    <div className="image-grain-overlay"></div>

                    <div className="absolute top-2 left-2 bg-white/95 backdrop-blur px-2 py-1 rounded-lg border border-orange-100 shadow-sm z-10">
                      <span className="text-[7px] font-black text-[#FF733B] uppercase tracking-wider">{item.condition}</span>
                    </div>

                    {!isOwner && (
                      <button 
                        onClick={(e) => toggleFavorite(e, item.id)}
                        className={`absolute top-2 right-2 p-1.5 rounded-full bg-white shadow-md transition-all active:scale-90 z-10 ${
                          burstingId === item.id ? 'animate-heart-burst' : ''
                        }`}
                      >
                        <svg 
                          xmlns="http://www.w3.org/2000/svg" 
                          className={`h-3.5 w-3.5 ${favorites.has(item.id) ? 'fill-[#FF733B] text-[#FF733B]' : 'text-[#FF733B]'}`} 
                          fill={favorites.has(item.id) ? "currentColor" : "none"} 
                          viewBox="0 0 24 24" 
                          stroke="currentColor"
                        >
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                        </svg>
                      </button>
                    )}
                  </div>

                  <div className="flex flex-col space-y-1 px-2 pb-2 h-20 justify-between">
                    <div>
                      <span className="text-[7px] font-black text-orange-400 uppercase tracking-[0.15em] block h-3 truncate leading-none">
                        {item.brand || item.category}
                      </span>

                      <h3 className="font-black text-[#1A1A1A] text-[11px] tracking-tight line-clamp-2 leading-tight min-h-[1.75rem] uppercase">
                        {item.title}
                      </h3>
                    </div>

                    <div className="flex justify-between items-baseline pt-1">
                      <span className="text-xs font-black text-[#FF733B] tracking-tighter shrink-0">
                        ${Number(item.price).toFixed(2)}
                      </span>
                      <span className="text-[7px] font-bold text-[#B0B0B0] uppercase tracking-wider text-right truncate flex-1 ml-2">
                        {item.location}
                      </span>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-20 text-center opacity-40">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 mb-4 text-gray-300" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
            </svg>
            <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">No results found</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Marketplace;

import React, { useState, useMemo, useEffect } from 'react';
import { supabase, isSupabaseConfigured } from '../lib/supabase';

interface ItemDetailProps {
  item: any;
  session: any;
  onBack: () => void;
  onFavoriteChange?: (isSaved: boolean) => void;
  onMessage: (conversationId?: string | null) => void;
}

const ItemDetail: React.FC<ItemDetailProps> = ({ item, session, onBack, onFavoriteChange, onMessage }) => {
  const [currentPhotoIdx, setCurrentPhotoIdx] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteSuccess, setDeleteSuccess] = useState(false);
  const [isMessaging, setIsMessaging] = useState(false);
  const [isFavorited, setIsFavorited] = useState(false);
  const [isBursting, setIsBursting] = useState(false);
  const [sellerProfile, setSellerProfile] = useState<{full_name: string, avatar_url: string, username: string} | null>(null);
  const [showConfirm, setShowConfirm] = useState(false);
  const [imageLoaded, setImageLoaded] = useState(false);

  const GENERIC_AVATAR = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 100 100'%3E%3Crect width='100' height='100' rx='35' fill='white'/%3E%3Crect x='2' y='2' width='96' height='96' rx='34' fill='none' stroke='%23FF8C42' stroke-width='1.5' stroke-opacity='0.2'/%3E%3Ccircle cx='50' cy='44' r='18' fill='%23B0B0B0'/%3E%3Cpath d='M22 86c0-15 12-25 28-25s28 10 28 25v4H22v-4z' fill='%23B0B0B0'/%3E%3C/svg%3E";

  const myId = session?.user?.id;
  const sellerId = item.seller_id;

  const isOwner = useMemo(() => {
    if (!myId || !sellerId) return false;
    return String(myId).trim().toLowerCase() === String(sellerId).trim().toLowerCase();
  }, [myId, sellerId]);

  const photos = useMemo(() => {
    if (!item.image_url) return [];
    try { 
      return item.image_url.startsWith('[') ? JSON.parse(item.image_url) as string[] : [item.image_url]; 
    } catch { 
      return [item.image_url]; 
    }
  }, [item.image_url]);

  useEffect(() => {
    const init = async () => {
      if (!isSupabaseConfigured) return;
      const [{data: seller}, {data: fav}] = await Promise.all([
        supabase.from('profiles').select('full_name, avatar_url, username').eq('id', item.seller_id).maybeSingle(),
        session?.user?.id ? supabase.from('favorites').select('id').eq('user_id', session.user.id).eq('listing_id', item.id).maybeSingle() : Promise.resolve({data: null})
      ]);
      if (seller) setSellerProfile(seller);
      setIsFavorited(!!fav);
    };
    init();
  }, [item.id, item.seller_id, session?.user?.id]);

  const nextPhoto = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    setImageLoaded(false);
    setCurrentPhotoIdx((prev) => (prev + 1) % photos.length);
  };

  const prevPhoto = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    setImageLoaded(false);
    setCurrentPhotoIdx((prev) => (prev - 1 + photos.length) % photos.length);
  };

  const toggleFavorite = async () => {
    if (!session?.user?.id) return;
    const next = !isFavorited;
    setIsFavorited(next);
    setIsBursting(true);
    setTimeout(() => setIsBursting(false), 400);
    onFavoriteChange?.(next);

    if (!next) {
      await supabase.from('favorites').delete().eq('user_id', session.user.id).eq('listing_id', item.id);
    } else {
      await supabase.from('favorites').insert({ user_id: session.user.id, listing_id: item.id });
    }
  };

  const handleMessageSeller = async () => {
    if (!session?.user?.id || isMessaging) return;
    setIsMessaging(true);
    try {
      const { data: found } = await supabase
        .from('conversations')
        .select('id, buyer_id, seller_id')
        .or(`buyer_id.eq.${session.user.id},seller_id.eq.${session.user.id}`);

      const existing = found?.find(c => 
        (c.buyer_id === session.user.id && c.seller_id === item.seller_id) || 
        (c.buyer_id === item.seller_id && c.seller_id === session.user.id)
      );

      if (existing) return onMessage(existing.id);

      const { data: created, error } = await supabase
        .from('conversations')
        .insert({ buyer_id: session.user.id, seller_id: item.seller_id, listing_id: item.id })
        .select()
        .single();

      if (created) onMessage(created.id);
      else if (error) throw error;
    } catch (err: any) {
      console.error('Messaging Error:', err);
    } finally { setIsMessaging(false); }
  };

  const performDelete = async () => {
    setShowConfirm(false);
    setIsDeleting(true);

    try {
      const { error, count } = await supabase
        .from('listings')
        .delete({ count: 'exact' })
        .eq('id', item.id)
        .eq('seller_id', myId);

      if (error || count === 0) throw new Error(error?.message || "Delete failed");

      setDeleteSuccess(true);
      setTimeout(() => onBack(), 1200);
    } catch (err: any) {
      setIsDeleting(false);
      alert('Delete Failed: Please refresh and try again.');
    }
  };

  const isClothing = item.category === 'Clothing';
  const displaySellerAvatar = sellerProfile?.avatar_url || GENERIC_AVATAR;

  return (
    <div className="h-full bg-white overflow-y-auto no-scrollbar pb-32">
      {showConfirm && (
        <div className="fixed inset-0 z-[100] flex items-end justify-center">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300" onClick={() => setShowConfirm(false)}></div>
          <div className="relative bg-white w-full max-w-md rounded-t-[2.5rem] p-10 shadow-2xl animate-in slide-in-from-bottom duration-400">
            <div className="w-12 h-1.5 bg-gray-100 rounded-full mx-auto mb-8"></div>
            <div className="text-center mb-10">
              <h2 className="text-2xl font-black text-gray-900 uppercase tracking-tight mb-2">Delete Item?</h2>
              <p className="text-sm text-gray-400 font-medium">This cannot be undone. Listing will be removed from the marketplace.</p>
            </div>
            <div className="space-y-3">
              <button onClick={performDelete} className="w-full bg-[#FF733B] text-white font-black py-5 rounded-[1.5rem] text-[11px] uppercase tracking-widest active:scale-95 transition-all">Confirm Delete</button>
              <button onClick={() => setShowConfirm(false)} className="w-full bg-gray-50 text-gray-500 font-black py-5 rounded-[1.5rem] text-[11px] uppercase tracking-widest active:scale-95 transition-all">Cancel</button>
            </div>
          </div>
        </div>
      )}

      <div className="relative bg-white pt-10 px-4">
        <div className="absolute top-10 left-6 z-20 flex w-full pr-12 justify-between items-center">
          <button onClick={onBack} className="bg-white/90 backdrop-blur-sm p-2.5 rounded-xl shadow-lg border-2 border-gray-100 active:scale-90 transition-all">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-gray-900" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
          </button>

          {!isOwner && (
            <button onClick={toggleFavorite} className={`bg-white/90 backdrop-blur-sm p-2.5 rounded-xl shadow-lg border-2 border-gray-100 active:scale-90 transition-all ${isBursting ? 'animate-heart-burst' : ''}`}>
              <svg xmlns="http://www.w3.org/2000/svg" className={`h-6 w-6 ${isFavorited ? 'fill-red-500 text-red-500' : 'text-gray-400'}`} fill={isFavorited ? "currentColor" : "none"} viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
            </button>
          )}
        </div>

        <div className="aspect-[4/5] flex items-center justify-center relative overflow-hidden rounded-[2.5rem] bg-gray-50 group border-2 border-gray-100 shadow-inner">
          {deleteSuccess ? (
            <div className="flex flex-col items-center animate-envelope-pop">
              <div className="bg-emerald-500 p-6 rounded-full mb-4 shadow-xl shadow-emerald-100"><svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={4} d="M5 13l4 4L19 7" /></svg></div>
              <p className="font-black text-emerald-600 uppercase tracking-widest text-[10px]">Item Deleted</p>
            </div>
          ) : (
            <>
              {/* Main Image */}
              <div className={`w-full h-full transition-opacity duration-300 ${imageLoaded ? 'opacity-100' : 'opacity-0'}`}>
                <img 
                  src={photos[currentPhotoIdx]} 
                  className="w-full h-full object-cover cursor-pointer" 
                  alt={item.title} 
                  onLoad={() => setImageLoaded(true)}
                  onClick={(e) => {
                    const rect = e.currentTarget.getBoundingClientRect();
                    const x = e.clientX - rect.left;
                    if (x > rect.width / 2) nextPhoto();
                    else prevPhoto();
                  }}
                />
              </div>

              {!imageLoaded && (
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-8 h-8 border-3 border-orange-200 border-t-orange-500 rounded-full animate-spin"></div>
                </div>
              )}

              {/* Pagination Dots */}
              {photos.length > 1 && (
                <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex space-x-1.5 bg-black/20 backdrop-blur-md px-3 py-2 rounded-full z-10">
                  {photos.map((_, idx) => (
                    <div key={idx} className={`h-1.5 transition-all duration-300 rounded-full ${idx === currentPhotoIdx ? 'w-4 bg-white' : 'w-1.5 bg-white/40'}`}></div>
                  ))}
                </div>
              )}
            </>
          )}
        </div>
      </div>

      <div className="px-6 mt-8 space-y-6">
