  const [errorType, setErrorType] = useState<'none' | 'table_missing'>('none');
  const scrollRef = useRef<HTMLDivElement>(null);

  const GENERIC_AVATAR = "https://t4.ftcdn.net/jpg/02/15/84/43/360_F_215844325_ttX9vtII6CHedAMhp8asW807z9vhS6CI.jpg";
  const currentUserId = session?.user?.id;

  const chatSetupSQL = `
-- Setup script for Marketplace Chat Infrastructure
CREATE TABLE IF NOT EXISTS public.conversations (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  listing_id uuid REFERENCES public.listings(id) ON DELETE CASCADE,
  buyer_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  seller_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS public.messages (
  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL,
  conversation_id uuid REFERENCES public.conversations(id) ON DELETE CASCADE,
  sender_id uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  text text NOT NULL
);

ALTER TABLE public.conversations ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.messages ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Users see conversations" on public.conversations;
create policy "Users see conversations" on public.conversations for select using (auth.uid() = buyer_id or auth.uid() = seller_id);
DROP POLICY IF EXISTS "Users start conversations" on public.conversations;
create policy "Users start conversations" on public.conversations for insert with check (auth.uid() = buyer_id);
DROP POLICY IF EXISTS "Users see messages" on public.messages;
create policy "Users see messages" on public.messages for select using (exists (select 1 from public.conversations where id = conversation_id and (buyer_id = auth.uid() or seller_id = auth.uid())));
DROP POLICY IF EXISTS "Users send messages" on public.messages;
create policy "Users send messages" on public.messages for insert with check (auth.uid() = sender_id);
  `.trim();

  useEffect(() => {
    if (currentUserId) {
      fetchConversations(currentUserId);
    } else {
      setLoading(false);
    }
  }, [currentUserId]);

  useEffect(() => {
    if (!initialConversationId || conversations.length === 0) return;
    const match = conversations.find((c) => c.id === initialConversationId);
    if (match) setSelectedConversation(match);
  }, [initialConversationId, conversations]);

  const fetchConversations = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('conversations')
        .select(`id, listing_id, buyer_id, seller_id, created_at`)
        .or(`buyer_id.eq.${userId},seller_id.eq.${userId}`)
        .order('created_at', { ascending: false });

      if (error) {
        if ((error as any).code === '42P01') setErrorType('table_missing');
        throw error;
      }

      if (data) {
        const grouped = data.reduce((acc: Conversation[], conv: any) => {
          const otherId = conv.buyer_id === userId ? conv.seller_id : conv.buyer_id;
          if (otherId === userId) return acc;
          const alreadyExists = acc.find(c => c.other_user_id === otherId);
          if (!alreadyExists) {
            acc.push({ ...conv, other_user_id: otherId });
          }
          return acc;
        }, []);

        setConversations(grouped);
        grouped.forEach((conv: any) => fetchAndCacheUserProfile(conv.other_user_id));
      }
    } catch (err: any) {
      console.error('Error fetching conversations:', err.message || err);
    } finally {
      setLoading(false);
    }
  };

  const fetchAndCacheUserProfile = async (userId: string) => {
    if (!userId) return;
    try {
      const { data: profile } = await supabase
        .from('profiles')
        .select('full_name, avatar_url, username')
        .eq('id', userId)
        .maybeSingle();

      if (profile) {
        const identity = profile.full_name || (profile.username ? `@${profile.username}` : `Student ${userId.slice(0, 4).toUpperCase()}`);
        setUserNames((s) => ({ ...s, [userId]: identity }));
        setUserHandles((s) => ({ ...s, [userId]: profile.username ? `@${profile.username}` : `student` }));
        if (profile.avatar_url) {
          setUserAvatars((s) => ({ ...s, [userId]: profile.avatar_url }));
        }
      }
    } catch (err) {}
  };

  const fetchMessages = async (convId: string) => {
    const { data, error } = await supabase
      .from('messages')
      .select('*')
      .eq('conversation_id', convId)
      .order('created_at', { ascending: true });
    if (error) console.error('Error fetching messages:', error.message || error);
    else setMessages(data || []);
  };

  useEffect(() => {
    if (!selectedConversation) return;
    fetchMessages(selectedConversation.id);
    const channel = supabase
      .channel(`chat-${selectedConversation.id}`)
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'messages',
        filter: `conversation_id=eq.${selectedConversation.id}`
      }, (payload) => {
        setMessages((prev) => {
          if (prev.some(m => m.id === payload.new.id)) return prev;
          return [...prev, payload.new as Message];
        });
      })
      .subscribe();
    return () => {
      supabase.removeChannel(channel);
    };
  }, [selectedConversation]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages]);

  const handleSendMessage = async () => {
    if (!inputValue.trim() || !selectedConversation || !currentUserId) return;
    const text = inputValue.trim();
    setInputValue('');
    await supabase.from('messages').insert({
      conversation_id: selectedConversation.id,
      sender_id: currentUserId,
      text: text
    });
  };

  const getUserDisplayName = (userId: string) => userNames[userId] || 'Student';
  const getUserHandle = (userId: string) => userHandles[userId] || '...';
  const getAvatar = (userId: string) => userAvatars[userId] || GENERIC_AVATAR;

  if (errorType === 'table_missing') {
    return (
      <div className="flex flex-col h-full bg-white p-8 justify-center items-center text-center space-y-4">
        <div className="bg-orange-50 p-6 rounded-[2rem] text-[#FF733B]">
          <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
          </svg>
        </div>
        <h2 className="text-xl font-black text-gray-900 uppercase tracking-tight">Setup Chat Infrastructure</h2>
        <pre className="bg-gray-900 text-emerald-400 p-4 rounded-2xl text-[8px] overflow-x-auto whitespace-pre font-mono h-48 w-full">{chatSetupSQL}</pre>
        <button onClick={() => window.location.reload()} className="w-full bg-[#FF733B] text-white py-4 rounded-2xl font-black uppercase tracking-widest text-[11px] active:scale-95 transition-all">Reload App</button>
      </div>
    );
  }

  if (selectedConversation) {
    return (
      <div className="flex flex-col h-full bg-white animate-in slide-in-from-right duration-300">
        <div className="pt-12 pb-4 px-6 flex items-center border-b border-gray-100 space-x-4 bg-white/80 backdrop-blur-md sticky top-0 z-50">
          <button onClick={() => setSelectedConversation(null)} className="p-2 -ml-2 text-gray-400">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" />
            </svg>
          </button>
          <div className="flex items-center space-x-3">
            <img src={getAvatar(selectedConversation.other_user_id)} className="w-10 h-10 rounded-full bg-gray-50 border border-gray-100 object-cover" alt="Avatar" />
            <h3 className="text-sm font-black text-gray-900 tracking-tight truncate">{getUserDisplayName(selectedConversation.other_user_id)}</h3>
          </div>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-4 no-scrollbar">
          {messages.map((msg) => {
            const isMe = msg.sender_id === currentUserId;
            return (
              <div key={msg.id} className={`flex ${isMe ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] px-5 py-3 rounded-[1.5rem] text-sm ${isMe ? 'bg-[#FF733B] text-white rounded-br-none shadow-lg shadow-orange-100/50' : 'bg-gray-100 text-gray-800 rounded-bl-none font-medium'}`}>
                  {msg.text}
                </div>
              </div>
            );
          })}
        </div>

        <div className="p-4 pb-28 bg-white border-t border-gray-100">
          <div className="flex items-center space-x-2 max-w-md mx-auto">
            <input type="text" value={inputValue} onChange={(e) => setInputValue(e.target.value)} onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()} placeholder="Type a message..." className="flex-1 bg-gray-50 border border-gray-100 rounded-2xl px-5 py-3.5 text-sm focus:ring-2 focus:ring-orange-100 outline-none" />
            <button onClick={handleSendMessage} className="bg-[#FF733B] text-white p-3.5 rounded-2xl shadow-lg shadow-orange-100 active:scale-90 transition-transform">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" /></svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-white overflow-hidden">
      <div className="pt-16 pb-6 px-8 border-b border-gray-50">
        <h1 className="text-4xl font-black text-gray-900 tracking-tight">Messages</h1>
      </div>
      <div className="flex-1 overflow-y-auto pb-24 p-4 space-y-3 bg-gray-50/30 no-scrollbar">
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-3">
            <div className="w-8 h-8 border-4 border-[#FF733B] border-t-transparent rounded-full animate-spin"></div>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Syncing Inbox...</p>
          </div>
        ) : conversations.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-32 text-gray-300 text-center px-8">
            <div className="bg-white p-8 rounded-[3rem] mb-6 shadow-sm border border-gray-100 opacity-50">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" /></svg>
            </div>
            <h3 className="text-gray-900 font-bold mb-1 text-lg uppercase tracking-tight">Inbox Empty</h3>
            <p className="text-xs font-medium text-gray-400">Message a student to start a chat</p>
          </div>
        ) : (
          conversations.map((chat) => (
            <div 
              key={chat.id} 
              onClick={() => setSelectedConversation(chat)}
              className="p-5 flex items-center space-x-4 bg-white rounded-[2rem] border border-gray-100 shadow-sm active:scale-[0.98] transition-all cursor-pointer hover:border-[#FF733B] group"
            >
              <img src={getAvatar(chat.other_user_id)} className="w-14 h-14 rounded-2xl bg-orange-50 border border-orange-100 object-cover" alt="Avatar" />
              <div className="flex-1 overflow-hidden">
                <h3 className="font-black text-gray-900 text-lg tracking-tight truncate">{getUserDisplayName(chat.other_user_id)}</h3>
                <span className="text-[10px] font-black text-[#FF733B] uppercase tracking-widest">{getUserHandle(chat.other_user_id)}</span>
              </div>
              <div className="text-[#FF733B] opacity-30 group-hover:opacity-100 transition-opacity">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" /></svg>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default Messages;

import React, { useState } from 'react';
